const ttsItem = $('Voice RSS').first();
const pexItem = $('Pexels').first();

const videos = pexItem.json.videos || [];
if (!videos.length) throw new Error('No Pexels videos found.');

const videoFiles = videos[0].video_files || [];
const portrait = videoFiles.find(f => f.width === 1080 && f.height === 1920)
  || videoFiles.find(f => f.height > f.width)
  || videoFiles[0];

const videoUrl = portrait.link;
const title = $('Parse Script & Keyword').first().json.title;

return [{
  json: {
    videoUrl,
    title: title.slice(0, 80),
    keyword: 'artificial intelligence technology',
    description: 'AI news in 45 seconds. Follow @Zyntelliq for daily AI updates.\n\n#AINews #Shorts #ArtificialIntelligence #Tech #Zyntelliq'
  },
  binary: {
    audioData: ttsItem.binary.data
  }
}];
